import Layout from "../../components/layout/Layout";

const UserDashboard = () => {
  return (

    <Layout>

      <h1>Dashboard</h1>

      <p>Welcome to Unified Resource Management System</p>

      <div>

        <p>Active Resources : 2</p>
        <p>Pending Requests : 1</p>
        <p>Notifications : 3</p>

      </div>

    </Layout>

  );
};

export default UserDashboard;
